+        for (int i = 0; i < size; i++) {
+            long adr = i * 2 + invar;
+            byte v = m.get(ValueLayout.JAVA_BYTE, adr);
+            m.set(ValueLayout.JAVA_BYTE, adr, (byte)(v + 1));
+        }
